import moment from 'moment';
import React, { useState, useEffect } from 'react';
import CountdownCard from './card/CountdownCard';
import Matchup from './matchup/Matchup';
import _ from 'lodash';
import { decompress } from 'compress-json';
import crypto from 'crypto';

import './App.css';

const algorithm = 'aes-256-ctr';
const secretKey = 'vOVH6sdmpNWjRRIqCc7rdxs01lwHzfr3';

const decrypt = (hash) => {
  const decipher = crypto.createDecipheriv(algorithm, secretKey, Buffer.from(hash.iv, 'hex'));
  return Buffer.concat([decipher.update(Buffer.from(hash.content, 'hex')), decipher.final()]).toString();
};

function App() {
  const dataFormat = 'YYYY/MM/DD hh:mm:ss';

  const [eventData, setEventData] = useState([]);
  const [timer, setTimer] = useState(0);
  const [matchupMode, setMatchupMode] = useState(false);

  useEffect(() => {
    fetch('data/data.json')
      .then((r) => r.json())
      .then((encJson) => {
        const json = JSON.parse(decrypt(encJson));
        const eventData = _.chain(decompress(json))
          .map(event => {
            const startDate = moment.utc(event.start_time, dataFormat)
            const endDate = moment.utc(event.end_time, dataFormat)
            return { ...event, startDate, endDate }
          })
          .orderBy(event => new moment(event.startDate))
          .value();
        setEventData(eventData)
      });

    setInterval(() => {
      setTimer(1);
    }, 1000);
    setMatchupMode(window.location.search === '?matchup');
  }, []);

  useEffect(() => {
    setTimer(0);
  }, [timer]);

  const content = (matchupMode) ? <Matchup /> : (
    <div className='card-container'>
      {
        eventData.map((event, index) => {
          const endDate = moment.utc(event.end_time, dataFormat)
          return (endDate.diff(moment()) > 0) ? <CountdownCard key={`${event.event_name}-${index}`} event={event} /> : null;
        })
      }
    </div>
  )

  return (
    <div className="App">
      {content}
    </div>
  );
}

export default App;
